import math


def minplot(X, Y, k):
    rows = max(X)
    cols = max(Y)
    grid = [[0]*(cols+1) for _ in range(rows+1)]

    for i in range(len(X)):
        grid[X[i]][Y[i]] = 1

    col_acc = grid.copy()
    for j in range(cols+1):
        for i in range(1,rows + 1):
            col_acc[i][j] += col_acc[i-1][j]

    min_perim = math.inf
    for i in range(rows+1):
        for i2 in range(i,rows+1):
            dic = {0:-1}
            acc = 0
            for j in range(cols+1):
                acc += col_acc[i2][j] - (col_acc[i-1][j] if i>0 else 0)
                if acc-k in dic:
                    min_perim = min(min_perim, 2*(j - dic[acc-k]) + 2*(i2-i+1))
                dic[acc] = j
    return min_perim


