int minCost(vector<int> &x, vector<int> &y, int k) {
    int n = x.size();
    vector<vector<int>> grid(101, vector<int>(101, 0));
    for(int i = 0; i < n; ++i) {
        grid[x[i]][y[i]]++;
    }
    int ans = INT32_MAX;
    // Iterating on columns. The optimal answer can include columns i...j
    // Implementation similar to 2D Kadane's algorithm
    for(int i = 0; i < 101; ++i) {
        vector<int> col_sum(101, 0);
        for(int j = i; j < 101; ++j) {
            for(int k = 0; k < 101; ++k) {
                col_sum[k] += grid[k][j];
            }
            ans = min(ans, findMinCostArray(col_sum, k, j - i + 1));
        }
    }
    return ans;
}

int findMinCostArray(vector<int> &arr, int k, int l) {
    // need to find shortest subarray with exact sum k
    // Cost = 2(l + b) where b is the size of the shortest subarray and l is the length of the rectangle
    unordered_map<int, int> mp;
    int sum = 0;
    int b = INT32_MAX;
    mp[0] = -1;
    for(int i = 0; i < 101; ++i) {
        sum += arr[i];
        if(sum < k) {
            mp[sum] = i;
            continue;
        }
        int extra = sum - k;
        if(mp.find(extra) != mp.end()) {
            b = min(b, i - mp[extra]);
        }
        mp[sum] = i;
    }
    return 2 * (l + b);
}

